import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function UserManagement() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    id: null,
    prefix: "Mr",
    fullName: "",
    phone: "",
    email: "",
    status: "",
    source: "",
    isConverted: false,
  });

  const [filters, setFilters] = useState({
    fullName: "",
    email: "",
    status: "",
    isConverted: "",
    phone: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const usersPerPage = 10;

  const modalRef = useRef(null);
  const navigate = useNavigate();

  /* ================= FETCH USERS ================= */
  function fetchUsers() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/users", {
        headers: { Authorization: "Bearer " + token },
      })
      .then(function (response) {
        if (response.data.success) {
          setUsers(response.data.data);
        } else {
          toast.error(response.data.error || "Failed to fetch users");
        }
      })
      .catch(function (err) {
        toast.error(err.response?.data?.error || "Error fetching users");
      })
      .finally(function () {
        setLoading(false);
      });
  }

  useEffect(
    function () {
      const token = Cookies.get("adminToken");
      if (!token) {
        navigate("/");
      } else {
        fetchUsers();
      }
    },
    [navigate],
  );

  /* ================= INPUT CHANGE ================= */
  function handleInputChange(e) {
    const { name, value } = e.target;

    setFormData((prev) => {
      const updated = { ...prev };
      if (name === "isConverted") {
        updated[name] = value === "true";
      } else {
        updated[name] = value;
      }
      return updated;
    });
  }

  /* ================= FILTER CHANGE ================= */
  function handleFilterChange(e) {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
    setCurrentPage(1); // Reset to first page whenever filters change
  }

  /* ================= EDIT ================= */
  function handleEdit(user) {
    setFormData({
      id: user.id,
      prefix: user.prefix,
      fullName: user.fullName,
      phone: user.phone,
      email: user.email,
      status: user.status,
      source: user.source,
      isConverted: user.isConverted,
    });

    const modalElement = document.getElementById("editUserModal");
    modalRef.current = new Modal(modalElement);
    modalRef.current.show();
  }

  /* ================= UPDATE ================= */
  function handleSubmit(e) {
    e.preventDefault();

    const token = Cookies.get("adminToken");

    axios
      .put(API_BASE_URL + "/users/" + formData.id, formData, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(function () {
        toast.success("User updated successfully");
        fetchUsers();
        modalRef.current.hide();
      })
      .catch(function (err) {
        toast.error(err.response?.data?.error || "Update failed");
      });
  }

  /* ================= DELETE ================= */
  function handleDelete(id) {
    if (!window.confirm("Are you sure you want to delete this user?")) {
      return;
    }

    const token = Cookies.get("adminToken");

    axios
      .delete(API_BASE_URL + "/users/" + id, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(function () {
        toast.success("User deleted successfully");
        fetchUsers();
      })
      .catch(function (err) {
        toast.error(err.response?.data?.error || "Delete failed");
      });
  }

  /* ================= FILTERED USERS ================= */
  const filteredUsers = users.filter((user) => {
    const isConverted = Boolean(user.isConverted); // ensure boolean

    return (
      user.fullName.toLowerCase().includes(filters.fullName.toLowerCase()) &&
      user.email.toLowerCase().includes(filters.email.toLowerCase()) &&
      (filters.status ? user.status === filters.status : true) &&
      (filters.isConverted
        ? isConverted === (filters.isConverted === "true")
        : true) &&
      user.phone.includes(filters.phone)
    );
  });

  /* ================= PAGINATION ================= */
  const indexOfLastUser = currentPage * usersPerPage;
  const indexOfFirstUser = indexOfLastUser - usersPerPage;
  const currentUsers = filteredUsers.slice(indexOfFirstUser, indexOfLastUser);
  const totalPages = Math.ceil(filteredUsers.length / usersPerPage);

  function goToNextPage() {
    if (currentPage < totalPages) setCurrentPage((prev) => prev + 1);
  }

  function goToPreviousPage() {
    if (currentPage > 1) setCurrentPage((prev) => prev - 1);
  }

  // Copy Phone
  function handleCopyPhone(phone) {
    navigator.clipboard
      .writeText(phone)
      .then(() => {
        toast.success("Phone number copied to clipboard");
      })
      .catch(() => {
        toast.error("Failed to copy phone number");
      });
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />
      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate("/dashboard")}
          ></i>
        </div>
      </div>

      <div className="row mb-3">
        <div className="col">
          <h4 className="fw-bold mb-0">User Management</h4>
        </div>
      </div>

      {/* ================= FILTERS ================= */}
      <div className="row g-3 mb-3">
        <div className="col-md-3 col-6">
          <input
            type="text"
            name="fullName"
            className="form-control"
            placeholder="Search by name"
            value={filters.fullName}
            onChange={handleFilterChange}
          />
        </div>

        <div className="col-md-3 col-6">
          <input
            type="text"
            name="phone"
            className="form-control"
            placeholder="Search by phone"
            value={filters.phone}
            onChange={handleFilterChange}
          />
        </div>
        <div className="col-md-3 col-6">
          <input
            type="text"
            name="email"
            className="form-control"
            placeholder="Search by email"
            value={filters.email}
            onChange={handleFilterChange}
          />
        </div>
        <div className="col-md-1 col-6">
          <select
            name="status"
            className="form-select"
            value={filters.status}
            onChange={handleFilterChange}
          >
            <option value="">Status</option>
            <option value="Client">Client</option>
            <option value="Lead">Lead</option>
          </select>
        </div>

        <div className="col-md-2 col-12">
          <select
            name="isConverted"
            className="form-select"
            value={filters.isConverted}
            onChange={handleFilterChange}
          >
            <option value="">All</option>
            <option value="true">Converted</option>
            <option value="false">Not Converted</option>
          </select>
        </div>
      </div>

      {/* ================= APPLIED FILTERS ================= */}
      <div className="row g-3 mb-3">
        <div className="col-auto">
          <span className="fw-semibold">Filters applied:</span>
        </div>

        {filters.fullName && (
          <div className="col-auto">
            <span className="badge bg-secondary">
              Name: {filters.fullName}{" "}
              <i
                className="fa fa-times ms-1"
                style={{ cursor: "pointer" }}
                onClick={() =>
                  setFilters((prev) => ({ ...prev, fullName: "" }))
                }
              ></i>
            </span>
          </div>
        )}

        {filters.phone && (
          <div className="col-auto">
            <span className="badge bg-secondary">
              Phone: {filters.phone}{" "}
              <i
                className="fa fa-times ms-1"
                style={{ cursor: "pointer" }}
                onClick={() => setFilters((prev) => ({ ...prev, phone: "" }))}
              ></i>
            </span>
          </div>
        )}

        {filters.email && (
          <div className="col-auto">
            <span className="badge bg-secondary">
              Email: {filters.email}{" "}
              <i
                className="fa fa-times ms-1"
                style={{ cursor: "pointer" }}
                onClick={() => setFilters((prev) => ({ ...prev, email: "" }))}
              ></i>
            </span>
          </div>
        )}

        {filters.status && (
          <div className="col-auto">
            <span className="badge bg-secondary">
              Status: {filters.status}{" "}
              <i
                className="fa fa-times ms-1"
                style={{ cursor: "pointer" }}
                onClick={() => setFilters((prev) => ({ ...prev, status: "" }))}
              ></i>
            </span>
          </div>
        )}

        {filters.isConverted && (
          <div className="col-auto">
            <span className="badge bg-secondary">
              Converted: {filters.isConverted === "true" ? "Yes" : "No"}{" "}
              <i
                className="fa fa-times ms-1"
                style={{ cursor: "pointer" }}
                onClick={() =>
                  setFilters((prev) => ({ ...prev, isConverted: "" }))
                }
              ></i>
            </span>
          </div>
        )}
      </div>

      <div className="card mb-3">
        <div className="card border-0">
          {loading ? (
            <div className="text-center">Loading...</div>
          ) : (
            <div className="table-responsive rounded">
              <table
                className="table table-striped table-hover mb-0 small"
                // style={{ fontSize: "14px" }}
              >
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    {/* <th>Prefix</th> */}
                    <th>Name</th>
                    <th>Phone</th>
                    <th>Email</th>
                    <th>Status</th>
                    <th>Source</th>
                    <th>Converted</th>
                    <th>Created At</th>
                    <th>Updated At</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {currentUsers.map((user) => (
                    <tr key={user.id}>
                      <td>{user.id}</td>
                      {/* <td>{user.prefix}</td> */}
                      {/* <td>{user.fullName}</td> */}
                      <td>{`${user.prefix} ${user.fullName}`}</td>
                      <td>
                        <i
                          className="fa-solid fa-phone text-success me-2"
                          style={{ cursor: "pointer" }}
                          title="Copy Phone Number"
                          onClick={() => handleCopyPhone(user.phone)}
                        ></i>
                      </td>

                      <td>{user.email}</td>
                      <td>{user.status}</td>
                      <td>{user.source}</td>
                      <td>{user.isConverted ? "Yes" : "No"}</td>
                      <td>{new Date(user.createdAt).toLocaleString()}</td>
                      <td>{new Date(user.updatedAt).toLocaleString()}</td>
                      <td>
                        <i
                          className="fa-solid fa-pen-to-square text-primary me-3"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleEdit(user)}
                          title="Edit User"
                        ></i>
                        <i
                          className="fa-solid fa-trash text-danger"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleDelete(user.id)}
                          title="Delete User"
                        ></i>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      {/* ================= PAGINATION CONTROLS ================= */}
      <div className="d-flex justify-content-between align-items-center mb-3">
        <div>
          Page {currentPage} of {totalPages}
        </div>
        <div>
          <button
            className="btn btn-sm border-0"
            onClick={goToPreviousPage}
            disabled={currentPage === 1}
          >
            <i className="fa-solid fa-chevron-left"></i>
          </button>
          <button
            className="btn btn-sm border-0"
            onClick={goToNextPage}
            disabled={currentPage === totalPages || totalPages === 0}
          >
            <i className="fa-solid fa-chevron-right"></i>
          </button>
        </div>
      </div>

      {/* ================= EDIT MODAL ================= */}
      <div className="modal fade" id="editUserModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <form onSubmit={handleSubmit}>
              <div className="modal-header">
                <h5 className="modal-title">Edit User</h5>
                <button
                  type="button"
                  className="btn-close"
                  data-bs-dismiss="modal"
                ></button>
              </div>

              <div className="modal-body">
                <div className="mb-3">
                  <label>Prefix</label>
                  <select
                    name="prefix"
                    className="form-select"
                    value={formData.prefix}
                    onChange={handleInputChange}
                  >
                    <option value="Mr">Mr</option>
                    <option value="Mrs">Mrs</option>
                    <option value="Miss">Miss</option>
                  </select>
                </div>

                <div className="mb-3">
                  <label>Full Name</label>
                  <input
                    type="text"
                    name="fullName"
                    className="form-control"
                    value={formData.fullName}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Phone</label>
                  <input
                    type="text"
                    name="phone"
                    className="form-control"
                    value={formData.phone}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Email</label>
                  <input
                    type="email"
                    name="email"
                    className="form-control"
                    value={formData.email}
                    onChange={handleInputChange}
                    required
                  />
                </div>

                <div className="mb-3">
                  <label>Status</label>
                  <select
                    name="status"
                    className="form-select"
                    value={formData.status}
                    onChange={handleInputChange}
                  >
                    <option value="Client">Client</option>
                    <option value="Lead">Lead</option>
                  </select>
                </div>

                <div className="mb-3">
                  <label>Source</label>
                  <input
                    type="text"
                    name="source"
                    className="form-control"
                    value={formData.source}
                    onChange={handleInputChange}
                  />
                </div>

                <div className="mb-3">
                  <label>Converted</label>
                  <select
                    name="isConverted"
                    className="form-select"
                    value={formData.isConverted ? "true" : "false"}
                    onChange={handleInputChange}
                  >
                    <option value="false">No</option>
                    <option value="true">Yes</option>
                  </select>
                </div>
              </div>

              <div className="modal-footer">
                <button type="submit" className="btn btn-primary">
                  Update
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

export default UserManagement;
